import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjRadioset } from "./OjRadioset";
export { OjRadioset };

/**
 * Create an instance of [[OjRadioset]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojRadioset(driver, By.id('my-oj-radioset'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojRadioset(driver: DriverLike, by: By): Promise<OjRadioset> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjRadioset
  if (!(webEl instanceof OjRadioset)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-radioset>`);
  }
  return webEl;
}

register("oj-radioset", OjRadioset);
